import{_ as e,c as a,o,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"OpenAI 額度: 查詢限額 | opencode-mystatus","description":"學習查詢 OpenAI ChatGPT 的 3 小時和 24 小時限額。解讀主視窗、次視窗、進度條和重置時間，掌握 Plus、Team、Pro 訂閱的額度差異，處理 Token 過期問題。","frontmatter":{"title":"OpenAI 額度: 查詢限額 | opencode-mystatus","sidebarTitle":"OpenAI 額度","subtitle":"OpenAI 額度: 查詢限額","description":"學習查詢 OpenAI ChatGPT 的 3 小時和 24 小時限額。解讀主視窗、次視窗、進度條和重置時間，掌握 Plus、Team、Pro 訂閱的額度差異，處理 Token 過期問題。","tags":["OpenAI","額度查詢","API 配額"],"prerequisite":["start-quick-start","start-understanding-output"],"order":1},"headers":[],"relativePath":"zh-tw/vbgate/opencode-mystatus/platforms/openai-usage/index.md","filePath":"zh-tw/vbgate/opencode-mystatus/platforms/openai-usage/index.md"}'),l={name:"zh-tw/vbgate/opencode-mystatus/platforms/openai-usage/index.md"};function i(s,t,r,d,p,c){return o(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="openai-額度查詢-3-小時和-24-小時限額" tabindex="-1">OpenAI 額度查詢：3 小時和 24 小時限額 <a class="header-anchor" href="#openai-額度查詢-3-小時和-24-小時限額" aria-label="Permalink to &quot;OpenAI 額度查詢：3 小時和 24 小時限額&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>使用 <code>/mystatus</code> 查詢 OpenAI Plus/Team/Pro 訂閱的額度</li><li>看懂輸出中的 3 小時和 24 小時限額資訊</li><li>理解主視窗和次視窗的區別</li><li>瞭解 Token 過期時的處理方式</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>OpenAI 的 API 呼叫有限額，超額後會被暫時限制存取。但你不知道：</p><ul><li>目前還剩多少額度？</li><li>3 小時和 24 小時視窗哪個在用？</li><li>什麼時候會重置？</li><li>為什麼有時候看到兩個視窗的資料？</li></ul><p>這些資訊如果不及時掌握，可能影響你用 ChatGPT 寫程式碼或做專案的進度。</p><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><p>當你：</p><ul><li>需要頻繁使用 OpenAI API 進行開發</li><li>發現回應變慢或被限流</li><li>想瞭解團隊帳號的使用情況</li><li>想知道什麼時候額度會重新整理</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>OpenAI 對 API 呼叫有兩種限流視窗：</p><table tabindex="0"><thead><tr><th>視窗類型</th><th>時長</th><th>作用</th></tr></thead><tbody><tr><td><strong>主視窗</strong>（primary）</td><td>由 OpenAI 伺服器端返回</td><td>防止短時間內大量呼叫</td></tr><tr><td><strong>次視窗</strong>（secondary）</td><td>由 OpenAI 伺服器端返回（可能不存在）</td><td>防止長期超額使用</td></tr></tbody></table><p>mystatus 會並行查詢這兩個視窗，顯示各自的：</p><ul><li>已使用百分比</li><li>剩餘額度進度條</li><li>距離重置的時間</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>視窗時長由 OpenAI 伺服器端返回，不同訂閱類型（Plus、Team、Pro）可能不同。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-執行查詢指令" tabindex="-1">第 1 步：執行查詢指令 <a class="header-anchor" href="#第-1-步-執行查詢指令" aria-label="Permalink to &quot;第 1 步：執行查詢指令&quot;">​</a></h3><p>在 OpenCode 中輸入 <code>/mystatus</code>，系統會自動查詢所有已配置平台的額度。</p><p><strong>你應該看到</strong>： 包含 OpenAI、智證 AI、Z.ai、Copilot、Google Cloud 等平台的額度資訊（取決於你配置了哪些平台）。</p><h3 id="第-2-步-找到-openai-部分" tabindex="-1">第 2 步：找到 OpenAI 部分 <a class="header-anchor" href="#第-2-步-找到-openai-部分" aria-label="Permalink to &quot;第 2 步：找到 OpenAI 部分&quot;">​</a></h3><p>在輸出中找到 <code>## OpenAI Account Quota</code> 部分。</p><p><strong>你應該看到</strong>： 類似這樣的內容：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3-hour limit</span></span>
<span class="line"><span>███████████████░░░░░░░░░░ 60% remaining</span></span>
<span class="line"><span>Resets in: 2h 30m</span></span></code></pre></div><h3 id="第-3-步-解讀主視窗資訊" tabindex="-1">第 3 步：解讀主視窗資訊 <a class="header-anchor" href="#第-3-步-解讀主視窗資訊" aria-label="Permalink to &quot;第 3 步：解讀主視窗資訊&quot;">​</a></h3><p><strong>主視窗</strong>（primary_window）通常顯示：</p><ul><li><strong>視窗名稱</strong>：如 <code>3-hour limit</code> 或 <code>24-hour limit</code></li><li><strong>進度條</strong>：直觀顯示剩餘額度的比例</li><li><strong>剩餘百分比</strong>：如 <code>60% remaining</code></li><li><strong>重置時間</strong>：如 <code>Resets in: 2h 30m</code></li></ul><p><strong>你應該看到</strong>：</p><ul><li>視窗名稱顯示時長（3 小時 / 24 小時）</li><li>進度條越滿代表剩餘越多，越空代表越快用完</li><li>重置時間是倒數計時，歸零後額度會重新整理</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>如果看到提示 <code>Limit reached!</code>，說明目前視窗額度已用完，需要等待重置。</p></div><h3 id="第-4-步-查看次視窗-如果有" tabindex="-1">第 4 步：查看次視窗（如果有） <a class="header-anchor" href="#第-4-步-查看次視窗-如果有" aria-label="Permalink to &quot;第 4 步：查看次視窗（如果有）&quot;">​</a></h3><p>如果 OpenAI 返回了次視窗資料，你會看到：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>24-hour limit</span></span>
<span class="line"><span>███████████████████████████ 90% remaining</span></span>
<span class="line"><span>Resets in: 20h 45m</span></span></code></pre></div><p><strong>你應該看到</strong>：</p><ul><li>次視窗顯示另一個時間維度的額度（通常是 24 小時）</li><li>可能與主視窗不同的剩餘百分比</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>次視窗是獨立的額度池，主視窗用完不影響次視窗，反之亦然。</p></div><h3 id="第-5-步-查看訂閱類型" tabindex="-1">第 5 步：查看訂閱類型 <a class="header-anchor" href="#第-5-步-查看訂閱類型" aria-label="Permalink to &quot;第 5 步：查看訂閱類型&quot;">​</a></h3><p>在 <code>Account</code> 行可以看到訂閱類型：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span>                                   ^^^^^</span></span>
<span class="line"><span>                                   訂閱類型</span></span></code></pre></div><p><strong>常見的訂閱類型</strong>：</p><ul><li><code>plus</code>：個人 Plus 訂閱</li><li><code>team</code>：團隊/組織訂閱</li><li><code>pro</code>：Pro 訂閱</li></ul><p><strong>你應該看到</strong>：</p><ul><li>你的帳號類型顯示在郵件後的括號裡</li><li>不同類型的限額可能不同</li></ul><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><p>驗證一下你理解了：</p><table tabindex="0"><thead><tr><th>場景</th><th>你應該看到</th></tr></thead><tbody><tr><td>主視窗剩餘 60%</td><td>進度條大約 60% 滿，顯示 <code>60% remaining</code></td></tr><tr><td>2.5 小時後重置</td><td>顯示 <code>Resets in: 2h 30m</code></td></tr><tr><td>達到限額</td><td>顯示 <code>Limit reached!</code></td></tr><tr><td>有次視窗</td><td>主視窗和次視窗各有一行資料</td></tr></tbody></table><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="❌-錯誤操作-token-過期後不重新整理" tabindex="-1">❌ 錯誤操作：Token 過期後不重新整理 <a class="header-anchor" href="#❌-錯誤操作-token-過期後不重新整理" aria-label="Permalink to &quot;❌ 錯誤操作：Token 過期後不重新整理&quot;">​</a></h3><p><strong>錯誤現象</strong>：看到提示 <code>⚠️ OAuth 授權已過期</code>（中文）或 <code>⚠️ OAuth token expired</code>（英文）</p><p><strong>原因</strong>：OAuth Token 已過期（由伺服器端控制的具體時長），過期後無法查詢額度。</p><p><strong>正確做法</strong>：</p><ol><li>在 OpenCode 中重新登入 OpenAI</li><li>Token 會自動重新整理</li><li>再次執行 <code>/mystatus</code> 查詢</li></ol><h3 id="❌-錯誤操作-混淆主視窗和次視窗" tabindex="-1">❌ 錯誤操作：混淆主視窗和次視窗 <a class="header-anchor" href="#❌-錯誤操作-混淆主視窗和次視窗" aria-label="Permalink to &quot;❌ 錯誤操作：混淆主視窗和次視窗&quot;">​</a></h3><p><strong>錯誤現象</strong>：以為只有一個視窗額度，結果主視窗用完次視窗還在用</p><p><strong>原因</strong>：兩個視窗是獨立的額度池。</p><p><strong>正確做法</strong>：</p><ul><li>關注兩個視窗各自的重置時間</li><li>主視窗重置快，次視窗重置慢</li><li>合理分配使用，避免某個視窗長期超額</li></ul><h3 id="❌-錯誤操作-忽略團隊帳號-id" tabindex="-1">❌ 錯誤操作：忽略團隊帳號 ID <a class="header-anchor" href="#❌-錯誤操作-忽略團隊帳號-id" aria-label="Permalink to &quot;❌ 錯誤操作：忽略團隊帳號 ID&quot;">​</a></h3><p><strong>錯誤現象</strong>：Team 訂閱顯示的不是自己的使用情況</p><p><strong>原因</strong>：Team 訂閱需要傳遞團隊帳號 ID，否則可能查詢的是預設帳號。</p><p><strong>正確做法</strong>：</p><ul><li>確保在 OpenCode 中登入了正確的團隊帳號</li><li>Token 中會自動包含 <code>chatgpt_account_id</code></li></ul><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>mystatus 透過呼叫 OpenAI 官方式 API 查詢額度：</p><ul><li>支援 OAuth 認證（Plus/Team/Pro）</li><li>顯示主視窗和次視窗（如果存在）</li><li>進度條可視化剩餘額度</li><li>倒數計時顯示重置時間</li><li>自動偵測 Token 過期</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../zhipu-usage/">智證 AI 和 Z.ai 額度查詢</a></strong>。</p><p>你會學到：</p><ul><li>5 小時 Token 限額是什麼</li><li>MCP 月度配額怎麼查看</li><li>使用率超過 80% 時的警告提示</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>OpenAI 額度查詢入口</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L207-L236" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>207-236</td></tr><tr><td>OpenAI API 呼叫</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L132-L155" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>132-155</td></tr><tr><td>格式化輸出</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L164-L194" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>164-194</td></tr><tr><td>JWT Token 解析</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L64-L73" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>64-73</td></tr><tr><td>提取使用者郵件</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L78-L81" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>78-81</td></tr><tr><td>Token 過期檢查</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L216-L221" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>216-221</td></tr><tr><td>OpenAIAuthData 類型定義</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L28-L33" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>28-33</td></tr></tbody></table><p><strong>常數</strong>：</p><ul><li><code>OPENAI_USAGE_URL = &quot;https://chatgpt.com/backend-api/wham/usage&quot;</code>：OpenAI 官方額度查詢 API</li></ul><p><strong>關鍵函數</strong>：</p><ul><li><code>queryOpenAIUsage(authData)</code>：查詢 OpenAI 額度的主函數</li><li><code>fetchOpenAIUsage(accessToken)</code>：呼叫 OpenAI API</li><li><code>formatOpenAIUsage(data, email)</code>：格式化輸出</li><li><code>parseJwt(token)</code>：解析 JWT Token（非標準函式庫實作）</li><li><code>getEmailFromJwt(token)</code>：從 Token 提取使用者郵件</li><li><code>getAccountIdFromJwt(token)</code>：從 Token 提取團隊帳號 ID</li></ul></details>`,70)])])}const b=e(l,[["render",i]]);export{u as __pageData,b as default};
